#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int Ai[N], Bi[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &Ai[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &Bi[i]);
        }
        long long maxProfit = 0;
        for (int i = 0; i < N; i++) {
            long long numStones = K / Ai[i];
            long long profit = numStones * Bi[i];
            maxProfit = (maxProfit > profit) ? maxProfit : profit;
        }
        printf("%lld\n", maxProfit);
    }
    return 0;
}

