code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] Ai = new int[N];
            int[] Bi = new int[N];
            for (int i = 0; i < N; i++) {
                Ai[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                Bi[i] = sc.nextInt();
            }
            long maxProfit = 0;
            for (int i = 0; i < N; i++) {
                long numStones = K / Ai[i];
                long profit = numStones * Bi[i];
                maxProfit = Math.max(maxProfit, profit);
            }
            System.out.println(maxProfit);
        }
    }
}

